function repairJSON(str) {
  str = str.trim();
  try { return JSON.parse(str); } catch(e) {}
  if (!str.startsWith('[')) { str = '[' + str; }
  const lastCompleteComma = str.lastIndexOf('},');
  const lastCompleteEnd = str.lastIndexOf('}]');
  let repaired = str;
  if (lastCompleteEnd > -1) {
    repaired = str.substring(0, lastCompleteEnd + 2);
  } else if (lastCompleteComma > -1) {
    repaired = str.substring(0, lastCompleteComma + 1) + ']';
  } else {
    repaired = str + ']';
  }
  try {
    return JSON.parse(repaired);
  } catch(e) {
    throw new Error('JSON repair failed: ' + e.message + '\nPreview: ' + str.substring(0, 300));
  }
}

