  const source = (img.source || '').toLowerCase();
  const link = (img.original || '').toLowerCase();
  return preferredSources.some(good =>
    source.includes(good) || link.includes(good)
  );
});

// ─── Final pool — priority order ─────────────────────────────
const pool = preferred.length > 0 ? preferred
           : clean.length > 0 ? clean
           : results;

// ─── Pick best valid URL per image ───────────────────────────
function getBestUrl(img) {

  // Original sometime Cloudflare blocked
  if (isValidImageUrl(img.original)) return img.original;
  // Thumbnail as fallback
    if (isValidImageUrl(img.thumbnail)) return img.thumbnail;

  return '';
}

